#include <stdio.h>
#include <math.h>
int main() {
    int T, N, x, y;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int points[N][2];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &points[i][0], &points[i][1]);
        }
        int count = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                for (int k = 0; k < N; k++) {
                    for (int l = k + 1; l < N; l++) {
                        if (i != k && i != l && j != k && j != l) {
                            double d1 = sqrt(pow(points[i][0] - points[j][0], 2) + pow(points[i][1] - points[j][1], 2));
                            double d2 = sqrt(pow(points[i][0] - points[k][0], 2) + pow(points[i][1] - points[k][1], 2));
                            double d3 = sqrt(pow(points[j][0] - points[l][0], 2) + pow(points[j][1] - points[l][1], 2));
                            double d4 = sqrt(pow(points[k][0] - points[l][0], 2) + pow(points[k][1] - points[l][1], 2));
                            double d5 = sqrt(pow(points[i][0] - points[k][0], 2) + pow(points[i][1] - points[k][1], 2));
                            double d6 = sqrt(pow(points[j][0] - points[k][0], 2) + pow(points[j][1] - points[k][1], 2));
                            if (d1 == d2 && d2 == d3 && d3 == d4 && d1 == d5 && d1 == d6) {
                                count++;
                            }
                        }
                    }
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

