                for (int j = i + 1; j < N; j++) {
                    for (int k = 0; k < N; k++) {
                        for (int l = k + 1; l < N; l++) {
                            if (i != k && i != l && j != k && j != l) {
                                double d1 = Math.sqrt(Math.pow(points[i][0] - points[j][0], 2) + Math.pow(points[i][1] - points[j][1], 2));
                                double d2 = Math.sqrt(Math.pow(points[i][0] - points[k][0], 2) + Math.pow(points[i][1] - points[k][1], 2));
                                double d3 = Math.sqrt(Math.pow(points[j][0] - points[l][0], 2) + Math.pow(points[j][1] - points[l][1], 2));
                                double d4 = Math.sqrt(Math.pow(points[k][0] - points[l][0], 2) + Math.pow(points[k][1] - points[l][1], 2));
                                double d5 = Math.sqrt(Math.pow(points[i][0] - points[k][0], 2) + Math.pow(points[i][1] - points[k][1], 2));
                                double d6 = Math.sqrt(Math.pow(points[j][0] - points[k][0], 2) + Math.pow(points[j][1] - points[k][1], 2));
